import React from "react";

const Values = {
    title: 'När du blir isolerad och fråntas ditt stödsystem',
    paragraphs: [
        'Gulderen berättar om hur hennes partner isolerade henne från hennes familj och vänner. Hon kände att hon inte fick något stöd och blev ensam. Detta påverkar fortfarande hennes relation till dem idag.',
    ],
    video: {
        title: 'Isoleringen och begränsade av supportsystemet',
        link: 'https://www.youtube-nocookie.com/embed/CfG3P3Vrn3A'
    },
    tips: {
        title: 'Tecken på våldsutsatthet:',
        list: [
            'Personen drar sig undan från vänner och inte längre vill följa med på aktiviteter.',
            'Personen blir mer tyst och inbunden.',
            'Personen verkar tyngd och bekymrad.',
            'Personen måste alltid passa tider.',
            'Personen måste redogöra för vad hen gjort och med vilka hen varit.',
            'Personen beter sig annorlunda när partnern är med.',
            'Personen inte säger emot sin partner.',
            'Personen verkar inte ha tillgång till egna pengar eller på annat sätt verkar vara beroende ekonomiskt av sin partner.',
        ],
        summary: <em>KÄLLA: <a href='https://1177.se'>1177.se</a></em>,
    },
    reflect: [
        'Ovan nämns några definitioner av våld, men det finns väldigt många. Kan du komma på en annan definition eller finns det något som du tycker är viktigt att nämna?',
        'Hur kan man som närstående stötta en person som blir isolerad av en partner?',
        'Varför är ett stödsystem så viktigt för en person som är utsatt för våld?',
    ],
}
export default Values;
